struct AhoCorasick {
    struct Node {
        map<char, int> next;  // 转移边
        int link = -1;        // 失配指针
        int dict_link = -1;   // 字典链接（指向最近模式串结尾）
        vector<int> ids;      // 以该节点结尾的模式串ID
        int cnt = 0;          // 匹配计数（根据题目需要）
    };
    vector<Node> nodes;

    AhoCorasick() { nodes.emplace_back(); }  // 根节点

    // 插入模式串
    void insert(const string &s, int id) {
        int v = 0;
        for (char ch : s) {
            if (!nodes[v].next.count(ch)) {
                nodes[v].next[ch] = nodes.size();
                nodes.emplace_back();
            }
            v = nodes[v].next[ch];
        }
        nodes[v].ids.push_back(id);
    }

    // 构建失配指针
    void build() {
        queue<int> q;
        q.push(0);
        while (!q.empty()) {
            int v = q.front(); q.pop();
            // 计算字典链接
            if (v != 0) {
                int u = nodes[v].link;
                nodes[v].dict_link = (nodes[u].ids.empty()) ? nodes[u].dict_link : u;
            }
            // BFS构建转移
            for (auto [ch, to] : nodes[v].next) {
                nodes[to].link = (v == 0) ? 0 : nodes[nodes[v].link].next[ch];
                q.push(to);
            } else {
                // 为当前节点补全转移函数
                nodes[v].next[ch] = (v == 0) ? 0 : nodes[nodes[v].link].next[ch];
            }
        }
    }

    // 多模式匹配主函数
    void process(const string &text, vector<int> &occurrences) {
        int v = 0;
        for (int i = 0; i < text.size(); ++i) {
            char ch = text[i];
            v = nodes[v].next[ch];
            // 处理所有匹配的模式串
            for (int u = v; u != -1; u = nodes[u].dict_link) {
                for (int id : nodes[u].ids) {
                    occurrences[id]++;  // 记录匹配
                }
            }
        }
    }
};

