struct RollingHash {
    using ull = unsigned long long;
    const ull B1 = 131, B2 = 137;
    const ull M1 = 1e9 + 7, M2 = 1e9 + 9;
    vector<ull> pow1, pow2, h1, h2;

    RollingHash(const string &s) {
        int n = s.size();
        pow1.resize(n + 1); pow2.resize(n + 1);
        h1.resize(n + 1); h2.resize(n + 1);
        pow1[0] = pow2[0] = 1;
        for (int i = 0; i < n; i++) {
            pow1[i + 1] = pow1[i] * B1 % M1;
            pow2[i + 1] = pow2[i] * B2 % M2;
            h1[i + 1] = (h1[i] * B1 + s[i]) % M1;
            h2[i + 1] = (h2[i] * B2 + s[i]) % M2;
        }
    }

    // 获取子串 [l, r) 的双哈希值
    pair<ull, ull> get(int l, int r) {
        ull v1 = (h1[r] - h1[l] * pow1[r - l] % M1 + M1) % M1;
        ull v2 = (h2[r] - h2[l] * pow2[r - l] % M2 + M2) % M2;
        return {v1, v2};
    }
};

