def find_next_palindrome_time(current: str) -> str:
    """寻找下一个回文时间（HH:MM格式）"""
    hh, mm = map(int, current.split(':'))
    while True:
        mm += 1
        if mm == 60:
            mm = 0
            hh = (hh + 1) % 24
        time_str = f"{hh:02d}:{mm:02d}"
        if time_str == time_str[::-1]:
            return time_str

def count_palindromic_indices(s: str) -> int:
    """统计删除一个字符后仍为回文的索引数（原串为回文）"""
    n = len(s)
    cnt = 0
    for i in range(n // 2):
        if s[i] == s[n - 1 - i]:
            cnt += 1
        else:
            break
    return cnt * 2 + (1 if n % 2 == 1 else 0)

def can_form_new_palindrome(s: str) -> bool:
    """判断是否能通过重排形成不同的回文串"""
    from collections import Counter
    cnt = Counter(s)
    odd_chars = sum(1 for v in cnt.values() if v % 2 == 1)
    return odd_chars <= 1 and len(cnt) >= 2

def split_into_palindromes(s: str, k: int) -> bool:
    """判断能否将字符串分成k个等长回文子串"""
    n = len(s)
    if n % k != 0:
        return False
    length = n // k
    for i in range(k):
        segment = s[i * length:(i + 1) * length]
        if not is_palindrome(segment):
            return False
    return True

