// 双哈希结构体
struct DoubleHash {
    vector<ll> pref1, pref2, pow1, pow2;
    ll mod1 = 1e9+7, mod2 = 1e9+9, base = 131;

    void init(const string &s) {
        int n = s.size();
        pref1.assign(n+1, 0);
        pref2.assign(n+1, 0);
        pow1.assign(n+1, 1);
        pow2.assign(n+1, 1);

        for(int i=0; i<n; i++) {
            pref1[i+1] = (pref1[i]*base + s[i]) % mod1;
            pref2[i+1] = (pref2[i]*base + s[i]) % mod2;
            pow1[i+1] = (pow1[i]*base) % mod1;
            pow2[i+1] = (pow2[i]*base) % mod2;
        }
    }

    pair<ll,ll> get_hash(int l, int r) { // [l, r]
        ll h1 = (pref1[r+1] - pref1[l]*pow1[r-l+1] % mod1 + mod1) % mod1;
        ll h2 = (pref2[r+1] - pref2[l]*pow2[r-l+1] % mod2 + mod2) % mod2;
        return {h1, h2};
    }
};

// 回文串处理类
class PalindromeProcessor {
    DoubleHash hash_forward, hash_reverse;
    string s;

public:
    void build(const string &str) {
        s = str;
        hash_forward.init(s);
        string rev = s;
        reverse(rev.begin(), rev.end());
        hash_reverse.init(rev);
    }

    // 判断子串[l,r]是否是回文
    bool is_palindrome(int l, int r) {
        int n = s.size();
        auto h1 = hash_forward.get_hash(l, r);
        auto h2 = hash_reverse.get_hash(n-1-r, n-1-l);
        return h1 == h2;
    }

    // 获取最长回文前缀/后缀
    int longest_pal_prefix() {
        for(int len = s.size(); len >= 1; len--) {
            if(is_palindrome(0, len-1)) return len;
        }
        return 0;
    }

    int longest_pal_suffix() {
        int n = s.size();
        for(int len = n; len >= 1; len--) {
            if(is_palindrome(n-len, n-1)) return len;
        }
        return 0;
    }
};

