// 核心数据结构：回文自动机（PAM）/回文树
struct PalindromicTree {
    struct Node {
        int len, link;          // 回文长度，后缀链接
        int next[26];           // 字符转移边
        int cnt;                // 出现次数
        Node(int l = 0, int lnk = 0) : len(l), link(lnk), cnt(0) {
            memset(next, 0, sizeof(next));
        }
    };
    vector<Node> t;
    string s;                   // 当前处理的字符串
    int last;                   // 上次插入后所在的节点
    int n;                      // 已插入字符数

    PalindromicTree() {
        t.push_back(Node(-1, 0));  // 奇根，长度为-1
        t.push_back(Node(0, 0));   // 偶根，长度为0
        last = 1;                   // 初始在偶根
        n = 0;
        s = "#";                   // 起始字符
    }

    // 获取后缀链接直到形成回文
    int get_link(int u) {
        while (s[n - t[u].len - 1] != s[n]) u = t[u].link;
        return u;
    }

    // 添加字符c（0-indexed字母）
    void add(char ch) {
        s += ch;
        n++;
        int c = ch - 'a';
        int cur = get_link(last);

        // 如果转移不存在，创建新节点
        if (!t[cur].next[c]) {
            int node = t.size();
            t.push_back(Node(t[cur].len + 2));
            t[node].link = t[get_link(t[cur].link)].next[c];
            if (t[node].link == 0) t[node].link = 1;  // 指向偶根
            t[cur].next[c] = node;
        }
        last = t[cur].next[c];
        t[last].cnt++;
    }

    // 统计所有回文出现次数（需要反向遍历）
    void count() {
        for (int i = t.size() - 1; i > 1; i--) {
            t[t[i].link].cnt += t[i].cnt;
        }
    }
};

// 辅助函数：Manacher算法（获取每个中心的最长回文半径）
vector<int> manacher(const string &s) {
    string t = "#";
    for (char c : s) { t += c; t += '#'; }
    int n = t.size();
    vector<int> p(n, 0);
    int center = 0, right = 0;
    for (int i = 1; i < n; i++) {
        int mirror = 2 * center - i;
        if (i < right) p[i] = min(right - i, p[mirror]);
        while (i + p[i] + 1 < n && i - p[i] - 1 >= 0 && 
               t[i + p[i] + 1] == t[i - p[i] - 1]) p[i]++;
        if (i + p[i] > right) {
            center = i;
            right = i + p[i];
        }
    }
    return p;
}

