int countPalindromicSubstrings(const string &s) {
    int n = s.size(), cnt = 0;
    for (int center = 0; center < 2 * n - 1; ++center) {
        int left = center / 2;
        int right = left + (center % 2);
        while (left >= 0 && right < n && s[left] == s[right]) {
            cnt++;
            left--, right++;
        }
    }
    return cnt;
}

