// Trie节点定义（可根据题目扩展）
struct TrieNode {
    int next[26]; // 子节点指针（小写字母）
    int fail;     // AC自动机失败指针
    int end;      // 结束标记（可存储模式串ID、计数等）
    TrieNode() {
        memset(next, -1, sizeof(next));
        fail = 0;
        end = 0;
    }
};

class AC_Automaton {
private:
    vector<TrieNode> trie;
    int root;

    // 插入一个模式串
    void insert(const string &s, int id) {
        int p = root;
        for (char ch : s) {
            int c = ch - 'a';
            if (trie[p].next[c] == -1) {
                trie[p].next[c] = trie.size();
                trie.emplace_back();
            }
            p = trie[p].next[c];
        }
        trie[p].end = id; // 可根据需求改为计数或其他信息
    }

    // 构建失败指针（BFS）
    void build() {
        queue<int> q;
        for (int i = 0; i < 26; ++i) {
            if (trie[root].next[i] != -1) {
                trie[trie[root].next[i]].fail = root;
                q.push(trie[root].next[i]);
            } else {
                trie[root].next[i] = root;
            }
        }
        while (!q.empty()) {
            int u = q.front(); q.pop();
            for (int i = 0; i < 26; ++i) {
                if (trie[u].next[i] != -1) {
                    trie[trie[u].next[i]].fail = trie[trie[u].fail].next[i];
                    q.push(trie[u].next[i]);
                } else {
                    trie[u].next[i] = trie[trie[u].fail].next[i];
                }
            }
            // 可选：合并end信息（如trie[u].end |= trie[trie[u].fail].end）
        }
    }

public:
    AC_Automaton() {
        trie.emplace_back(); // 根节点
        root = 0;
    }

    // 初始化：插入所有模式串并构建AC自动机
    void init(const vector<string> &patterns) {
        for (int i = 0; i < patterns.size(); ++i) {
            insert(patterns[i], i + 1);
        }
        build();
    }

    // 查询主串text，返回匹配结果（根据题目需求实现）
    vector<int> query(const string &text) {
        vector<int> res;
        int p = root;
        for (int i = 0; i < text.size(); ++i) {
            int c = text[i] - 'a';
            p = trie[p].next[c];
            int tmp = p;
            while (tmp != root) {
                if (trie[tmp].end) {
                    // 找到匹配，记录位置i、模式串ID等
                    res.push_back(trie[tmp].end);
                }
                tmp = trie[tmp].fail;
            }
        }
        return res;
    }
};

