class StringHash {
private:
    using ull = unsigned long long;
    const int base = 131; // 常用质数基数
    vector<ull> hash, power;

    void build(const string &s) {
        int n = s.length();
        hash.resize(n + 1);
        power.resize(n + 1);
        power[0] = 1;
        for (int i = 1; i <= n; i++) {
            hash[i] = hash[i-1] * base + s[i-1];
            power[i] = power[i-1] * base;
        }
    }

    ull getHash(int l, int r) { // [l, r] 闭区间
        return hash[r+1] - hash[l] * power[r-l+1];
    }

    // 可选：双哈希增强
    vector<ull> hash2;
    const int base2 = 13331;
    vector<ull> power2;

    void buildDouble(const string &s) {
        build(s);
        int n = s.length();
        hash2.resize(n + 1);
        power2.resize(n + 1);
        power2[0] = 1;
        for (int i = 1; i <= n; i++) {
            hash2[i] = hash2[i-1] * base2 + s[i-1];
            power2[i] = power2[i-1] * base2;
        }
    }

    pair<ull, ull> getDoubleHash(int l, int r) {
        return {getHash(l, r), hash2[r+1] - hash2[l] * power2[r-l+1]};
    }
};

