bool isPeriodic(const string &s, int len) {
    // 检测 len 是否为 s 的周期
    int n = s.length();
    if (n % len != 0) return false;
    StringHash sh;
    sh.build(s);
    ull firstHash = sh.getHash(0, len-1);
    for (int i = len; i < n; i += len) {
        if (sh.getHash(i, i+len-1) != firstHash) {
            return false;
        }
    }
    return true;
}

