// KMP 前缀函数模板
vector<int> prefix_function(const string &s) {
    int n = s.size();
    vector<int> pi(n, 0);
    for (int i = 1; i < n; i++) {
        int j = pi[i - 1];
        while (j > 0 && s[i] != s[j]) {
            j = pi[j - 1];
        }
        if (s[i] == s[j]) {
            j++;
        }
        pi[i] = j;
    }
    return pi;
}

// Z 函数模板
vector<int> z_function(const string &s) {
    int n = s.size();
    vector<int> z(n, 0);
    int l = 0, r = 0;
    for (int i = 1; i < n; i++) {
        if (i <= r) {
            z[i] = min(r - i + 1, z[i - l]);
        }
        while (i + z[i] < n && s[z[i]] == s[i + z[i]]) {
            z[i]++;
        }
        if (i + z[i] - 1 > r) {
            l = i;
            r = i + z[i] - 1;
        }
    }
    return z;
}

// 使用前缀函数进行模式匹配（KMP）
vector<int> kmp_search(const string &text, const string &pattern) {
    string combined = pattern + '#' + text;
    vector<int> pi = prefix_function(combined);
    vector<int> matches;
    int p_len = pattern.size();
    for (int i = p_len + 1; i < combined.size(); i++) {
        if (pi[i] == p_len) {
            matches.push_back(i - 2 * p_len);
        }
    }
    return matches;
}

